import{_ as a,o as n,c as s,a5 as i}from"./chunks/framework.QFIuQCaY.js";const f=JSON.parse('{"title":"common/lcs-diff","description":"","frontmatter":{},"headers":[],"relativePath":"api/common.lcs-diff.md","filePath":"api/common.lcs-diff.md"}'),o={name:"api/common.lcs-diff.md"};function l(c,e,t,d,r,p){return n(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="common-lcs-diff" tabindex="-1">common/lcs-diff <a class="header-anchor" href="#common-lcs-diff" aria-label="Permalink to &quot;common/lcs-diff&quot;">​</a></h1><p>LCS(Longest Common Subsequence) 기반 깊은 비교 유틸리티</p><p><code>DomainState</code>의 <code>lazy</code> tracking mode에서 <code>save()</code> 호출 시, 인스턴스 생성 시점에 저장된 <code>_initialSnapshot</code>과 현재 도메인 객체를 비교하여 RFC 6902 형식의 <code>changeLog</code> 배열을 생성한다.</p><h2 id="realtime-모드와의-차이" tabindex="-1"><code>realtime</code> 모드와의 차이 <a class="header-anchor" href="#realtime-모드와의-차이" aria-label="Permalink to &quot;\`realtime\` 모드와의 차이&quot;">​</a></h2><p><code>realtime</code> 모드에서는 Proxy <code>set</code> 트랩이 발화될 때마다 changeLog에 즉시 기록한다. <code>lazy</code> 모드에서는 set 트랩 기록을 건너뛰고, <code>save()</code> 시점에 이 유틸로 한 번에 계산한다. 동일한 필드를 10번 바꿔도 최종 변경 결과만 1개 항목으로 기록되어 네트워크 페이로드가 최소화된다.</p><h2 id="배열-비교-전략" tabindex="-1">배열 비교 전략 <a class="header-anchor" href="#배열-비교-전략" aria-label="Permalink to &quot;배열 비교 전략&quot;">​</a></h2><ul><li><code>itemKey</code> 지정 시: LCS 알고리즘으로 항목 동일성(itemKey 필드값 기준)을 판단한다. 위치가 달라도 같은 항목으로 인식하며, 삭제/추가가 정확히 구분된다.</li><li><code>itemKey</code> 미지정 시: 위치(positional) 기준 비교를 수행한다. 같은 위치의 값이 달라지면 &#39;replace&#39;로 기록한다.</li></ul><h2 id="itemkey-필요성-예시" tabindex="-1"><code>itemKey</code> 필요성 예시 <a class="header-anchor" href="#itemkey-필요성-예시" aria-label="Permalink to &quot;\`itemKey\` 필요성 예시&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>초기: [{ id: 1, name: &#39;A&#39; }, { id: 2, name: &#39;B&#39; }]</span></span>
<span class="line"><span>현재: [{ id: 2, name: &#39;B&#39; }, { id: 3, name: &#39;C&#39; }]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>positional(오류):</span></span>
<span class="line"><span>  index 0: id:1 → id:2 → &#39;replace&#39;</span></span>
<span class="line"><span>  index 1: id:2 → id:3 → &#39;replace&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>LCS(itemKey=&#39;id&#39;, 정확):</span></span>
<span class="line"><span>  id:1 → 초기에만 있음 → &#39;remove&#39;</span></span>
<span class="line"><span>  id:2 → 양쪽에 있음  → no-op</span></span>
<span class="line"><span>  id:3 → 현재에만 있음 → &#39;add&#39;</span></span></code></pre></div><h2 id="see" tabindex="-1">See <a class="header-anchor" href="#see" aria-label="Permalink to &quot;See&quot;">​</a></h2><ul><li><a href="https://www.cs.columbia.edu/~allen/S14/NOTES/lcs.pdf" target="_blank" rel="noreferrer">LCS 알고리즘 참조</a></li><li><a href="https://www.rfc-editor.org/rfc/rfc6902" target="_blank" rel="noreferrer">RFC 6902 — JSON Patch</a></li></ul><h2 id="interfaces" tabindex="-1">Interfaces <a class="header-anchor" href="#interfaces" aria-label="Permalink to &quot;Interfaces&quot;">​</a></h2><ul><li><a href="./common.lcs-diff.Interface.ChangeLogEntry.html">ChangeLogEntry</a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><ul><li><a href="./common.lcs-diff.Function.deepDiff.html">deepDiff</a></li></ul>`,15)])])}const h=a(o,[["render",l]]);export{f as __pageData,h as default};
